#!/bin/sh
# cargo-loco-generate/cargo-loco-generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding heart-health-check (15 tables)..."

cargo loco generate scaffold patient \
    deleted_at:ts \
    name:string! \
    birth_date:date \
    united_kingdom_nhs_number:string^ \
    waist_as_cm:double \
    height_as_cm:double \
    weight_as_kg:double \
    body_mass_index:double \
    waist_height_ratio:double \
    vo2_max:double \
    --htmx && \
cargo loco generate scaffold clinician \
    deleted_at:ts \
    name:text! \
    role:text! \
    registration_body:text! \
    registration_number:text! \
    united_kingdom_nhs_number:string^ \
    --htmx && \
cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx && \
cargo loco generate scaffold demographics_ethnicity \
    assessment:references \
    age:int \
    sex:string! \
    ethnicity:string! \
    townsend_deprivation:double \
    --htmx && \
cargo loco generate scaffold blood_pressure \
    assessment:references \
    systolic_bp:int \
    systolic_bp_sd:double \
    diastolic_bp:int \
    on_bp_treatment:string! \
    number_of_bp_medications:int \
    --htmx && \
cargo loco generate scaffold cholesterol \
    assessment:references \
    total_cholesterol:double \
    hdl_cholesterol:double \
    total_hdl_ratio:double \
    on_statin:string! \
    --htmx && \
cargo loco generate scaffold medical_conditions \
    assessment:references \
    has_diabetes:string! \
    has_atrial_fibrillation:string! \
    has_rheumatoid_arthritis:string! \
    has_chronic_kidney_disease:string! \
    has_migraine:string! \
    has_severe_mental_illness:string! \
    has_erectile_dysfunction:string! \
    on_atypical_antipsychotic:string! \
    on_corticosteroids:string! \
    --htmx && \
cargo loco generate scaffold family_history \
    assessment:references \
    family_cvd_under_60:string! \
    family_cvd_relationship:string! \
    family_diabetes_history:string! \
    --htmx && \
cargo loco generate scaffold smoking_alcohol \
    assessment:references \
    smoking_status:string! \
    cigarettes_per_day:int \
    years_since_quit:int \
    alcohol_units_per_week:double \
    alcohol_frequency:string! \
    --htmx && \
cargo loco generate scaffold physical_activity_diet \
    assessment:references \
    physical_activity_minutes_per_week:int \
    activity_intensity:string! \
    fruit_veg_portions_per_day:int \
    diet_quality:string! \
    salt_intake:string! \
    --htmx && \
cargo loco generate scaffold body_measurements \
    assessment:references \
    height_cm:double \
    weight_kg:double \
    bmi:double \
    waist_circumference_cm:double \
    --htmx && \
cargo loco generate scaffold review_calculate \
    assessment:references \
    clinician_name:string! \
    review_date:date \
    clinical_notes:text! \
    audit_score:int \
    --htmx && \
cargo loco generate scaffold grading_result \
    assessment:references \
    risk_category:string! \
    ten_year_risk_percent:double! \
    heart_age:int \
    graded_at:ts \
    --htmx && \
cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    risk_level:string! \
    --htmx && \
cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
